{
  "success": true,
  "data": "{
  "query": "ERCOT annual wind generation 2020 2021 2022 2023 2024 TWh",
  "num_results": 5,
  "results": [
    {
      "url": "https://www.potomaceconomics.com/wp-content/uploads/2025/06/2024-State-of-the-Market-Report.pdf",
      "title": "2024 ERCOT",
